@strawberry.type
class Query:
    @strawberry.field
    def product(self, info, id: int) -> Optional[ProductType]:
        db = SessionLocal()
        try:
            return db.query(Product).filter(Product.id == id).first()
        finally:
            db.close()
    
    @strawberry.field
    def products(self, info, limit: Optional[int] = None, offset: Optional[int] = None) -> List[ProductType]:
        db = SessionLocal()
        try:
            query = db.query(Product)
            if limit:
                query = query.limit(limit)
            if offset:
                query = query.offset(offset)
            return query.all()
        finally:
            db.close()
    
    @strawberry.field
    def category(self, info, id: int) -> Optional[CategoryType]:
        db = SessionLocal()
